import asyncio, anthropic, json, time

client = anthropic.AsyncAnthropic()

class HOTLAgent:
    """
    Human-on-the-Loop agent: executes autonomously, emits events,
    checks for an interrupt signal before each tool call.
    """
    def __init__(self, session_id: str, emitter: EventEmitter):
        self.session_id = session_id
        self.emitter    = emitter
        self._stop      = asyncio.Event()
        self._executed: list[tuple[str, dict, Any]] = []  # (name, args, result)

    def interrupt(self) -> None:
        """Set by the monitoring UI or anomaly detector to stop the agent."""
        self._stop.set()

    async def run(
        self,
        task:      str,
        tools:     list[dict],
        executor:  Any,
        rollback:  Any | None = None,
    ) -> str:
        messages = [{'role': 'user', 'content': task}]

        while True:
            # Check interrupt before each model call
            if self._stop.is_set():
                return await self._abort(rollback)

            response = await client.messages.create(
                model="claude-opus-4-8",
                max_tokens=2048,
                tools=tools,
                messages=messages,
            )
            messages.append({'role': 'assistant', 'content': response.content})

            if response.stop_reason == 'end_turn':
                await self.emitter.emit(AgentEvent(EventType.SESSION_ENDED, self.session_id, 0))
                return next(b.text for b in response.content if b.type == 'text')

            tool_results = []
            for block in response.content:
                if block.type != 'tool_use':
                    continue

                # Interrupt check before each individual tool call
                if self._stop.is_set():
                    return await self._abort(rollback)

                await self.emitter.emit(AgentEvent(
                    EventType.ACTION_STARTED, self.session_id, 0,
                    tool_name=block.name, tool_input=block.input,
                ))

                t0 = time.monotonic()
                try:
                    result = await executor(block.name, block.input)
                    elapsed = int((time.monotonic() - t0) * 1000)
                    self._executed.append((block.name, block.input, result))
                    await self.emitter.emit(AgentEvent(
                        EventType.ACTION_COMPLETED, self.session_id, 0,
                        tool_name=block.name, tool_output=result, latency_ms=elapsed,
                    ))
                except Exception as e:
                    await self.emitter.emit(AgentEvent(
                        EventType.ACTION_FAILED, self.session_id, 0,
                        tool_name=block.name, anomaly=str(e),
                    ))
                    raise

                tool_results.append({
                    'type': 'tool_result',
                    'tool_use_id': block.id,
                    'content': json.dumps(result),
                })

            messages.append({'role': 'user', 'content': tool_results})

    async def _abort(self, rollback: Any | None) -> str:
        if rollback:
            for name, args, result in reversed(self._executed):
                try:
                    await rollback(name, args, result)
                except Exception as e:
                    print(f'[rollback failed] {name}: {e}')
        return 'Session interrupted and rolled back by human reviewer.'

from fastapi import FastAPI
from fastapi.responses import StreamingResponse, JSONResponse
import asyncio

app = FastAPI()
_agents: dict[str, HOTLAgent] = {}

@app.get('/stream/{session_id}')
async def stream_events(session_id: str):
    """SSE endpoint: client subscribes and receives all agent events live."""
    agent = _agents.get(session_id)
    if not agent:
        return JSONResponse({'error': 'not found'}, status_code=404)

    queue = agent.emitter.subscribe()

    async def event_generator():
        while True:
            event: AgentEvent = await queue.get()
            yield event.to_sse()
            if event.event_type == EventType.SESSION_ENDED:
                break

    return StreamingResponse(
        event_generator(),
        media_type="text/event-stream",
        headers={"Cache-Control": "no-cache", "X-Accel-Buffering": "no"},
    )

@app.post('/interrupt/{session_id}')
async def interrupt_agent(session_id: str):
    """Called by the dashboard STOP button or the anomaly detector."""
    agent = _agents.get(session_id)
    if not agent:
        return JSONResponse({'error': 'not found'}, status_code=404)
    agent.interrupt()
    return JSONResponse({'status': 'interrupt signal sent'})
